//#region Types/ColorPicker/ColorPickerInterop.ts
function getRelativePosition(element, clientX, clientY) {
	const rect = element.getBoundingClientRect();
	const w = rect.width || 1;
	const h = rect.height || 1;
	return [Math.max(0, Math.min(rect.width, clientX - rect.left)) / w, Math.max(0, Math.min(rect.height, clientY - rect.top)) / h];
}
//#endregion
export { getRelativePosition };